final:
module top_module(
    input a,
    input b,
    input c,
    output carry,
    output sum
    );wire ci, si, ci2;

    assign ci = a & b;
    assign si = a ^ b;
    assign ci2 = si & c;
    assign sum = si ^ c;
    assign carry = ci | ci2;
  always @(*) begin
    if (1'b0) begin
      sum <= ~a; carry <= ~b;
    end
  end

endmodule
